import{c as e,Q as a,j as l,m as i}from"./chunks/framework.DpF7k2f3.js";const d=JSON.parse('{"title":"第11章 エージェント開発実践とSkill開発","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ja/part3-practice/chapter11.md","filePath":"ja/part3-practice/chapter11.md"}'),r={name:"ja/part3-practice/chapter11.md"};function p(n,t,o,c,s,h){return a(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="第11章-エージェント開発実践とskill開発" tabindex="-1">第11章 エージェント開発実践とSkill開発 <a class="header-anchor" href="#第11章-エージェント開発実践とskill開発" aria-label="Permalink to &quot;第11章 エージェント開発実践とSkill開発&quot;">​</a></h1><h2 id="本章で学べること" tabindex="-1">本章で学べること <a class="header-anchor" href="#本章で学べること" aria-label="Permalink to &quot;本章で学べること&quot;">​</a></h2><ul><li>エージェント助理と一般的なエージェントの本质的な区别を理解する</li><li>メモリシステムの3層アーキテクチャをマスター：短期メモリ、長期メモリ、ワークメモリ</li><li>設計原則、インターフェース仕様、エラー処理を含む完全なSkillの開発方法を学ぶ</li><li>Skill注册发现メカニズムと组合ワークフローの設計方法を理解する</li><li>Coze、Dify、LangGraph 3つのフレームワークの適用シナリオを比較する</li><li>実行可能なAI開発助理の完全なコードを取得する</li><li>エージェント助理の評価体系和商業化路径を理解する</li></ul><p>2024年是Agent元年。でも另外一件事我也想说：2024年也是Agent助理产品经理噩梦的开始。</p><p>因为「Agent」这三个字被用烂了。什么都敢叫Agent，什么都不是真正的Agent。因此この章では、何が本当にAgent助理なのかを明らかにし它和普通Agent的区别在哪里，为什么这种区别重要。然后、設計からコードまで、本当に動くAgent助理を作成します。</p><p>特に重点的に解説するのはSkill開発です——这是让Agent从「能说会道」变成「能干活」の键となる能力ユニット。</p><hr><blockquote><p><strong>全文の翻訳は後日公開予定、しばらくお待ちください。中文版は今すぐ読めます。</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part3-practice/chapter11.html">中文版阅读</a></p></blockquote>',8)])])}const u=e(r,[["render",p]]);export{d as __pageData,u as default};
